# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, jsonify, request
from web3 import Web3, IpcProvider
import eth_utils

app = Flask(__name__)
w3 = Web3(IpcProvider('/path/to/geth.ipc'))

@app.route('/authenticate', methods=['POST'])
def authenticate():
    signed_msg = request.json['signed_msg']
    signature = eth_utils.to_bytes(request.json['signature']).hex()
    message_hash = eth_utils.to_keccak256(eth_utils.to_utf8(request.json['message']))
    recovered_address = w3.eth.account.recover_from_signed_message(msgparams=message_hash, sigs=[signature])
    return jsonify({'authenticated': bool(w3.toChecksumAddress(recovered_address) in set(accounts))})

if __name__ == '__main__':
    # List of account addresses for authentication (replace with your own)
    accounts = ['0xYourAccount1', '0xYourAccount2']
    app.run(port=5000, threaded=True)